:root {
  /* Color system */
  --color-primary-1: #138A4F;
  --color-primary-2: #0C5E34;
  --color-secondary-1: #5BBF7B;
  --color-secondary-2: #2F9654;
  --color-accent: #138A4F;
  --color-bg: #FFFFFF;
  --color-text-main: #111111;
  --color-border-subtle: #E5E5E5;

  /* Typography */
  --font-heading: 'Libre Franklin', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --sidebar-width: 260px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  height: 100%;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-bg);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.page {
  min-height: 100vh;
  display: flex;
}

/* Sidebar header with logo and vertical navigation */

.site-header {
  width: var(--sidebar-width);
  padding: var(--space-4) var(--space-3) var(--space-5);
  flex-shrink: 0;
}

.site-logo {
  display: inline-block;
  margin-bottom: var(--space-4);
}

/* Ornate green plaque simulation */
.logo-plaque {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 160px;
  height: 80px;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 14px;
  letter-spacing: 0.12em;
  text-transform: none;
  color: #f7f7f7;
  background: radial-gradient(circle at 20% 20%, #5BBF7B 0%, #2F9654 35%, #0C5E34 100%);
  border-radius: 24px;
  border: 2px solid #0C5E34;
  box-shadow: 0 0 0 2px #138A4F inset;
}

.site-nav {
  margin-top: var(--space-2);
}

.nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
}

.nav-item + .nav-item {
  margin-top: var(--space-1);
}

.nav-link {
  display: inline-block;
  padding: var(--space-0-5) 0;
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-text-main);
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-accent);
  text-decoration: none;
}

.nav-link--active {
  font-weight: var(--font-weight-semibold);
  color: var(--color-accent);
}

/* Main content area */

.site-main {
  flex: 1;
  padding: var(--space-5) var(--space-6) var(--space-6);
  position: relative;
}

.main-top-rule {
  border-top: 1px solid var(--color-border-subtle);
  margin-top: var(--space-1);
  margin-bottom: var(--space-4);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  padding: var(--space-3) var(--space-6) var(--space-4);
  font-size: var(--font-size-small);
  font-family: var(--font-heading);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1) var(--space-2);
}

.footer-link {
  color: var(--color-text-main);
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-accent);
  text-decoration: none;
}

/* Utility: visually hidden (for potential future headings) */

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

/* Responsive adjustments */

@media (max-width: 768px) {
  .page {
    flex-direction: column;
  }

  .site-header {
    width: 100%;
    display: flex;
    align-items: flex-start;
    padding: var(--space-2) var(--space-2) var(--space-3);
    border-bottom: 1px solid var(--color-border-subtle);
  }

  .site-logo {
    margin-bottom: 0;
    margin-right: var(--space-3);
  }

  .site-nav {
    margin-top: 0;
    flex: 1;
  }

  .nav-list {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-1) var(--space-2);
  }

  .nav-item + .nav-item {
    margin-top: 0;
  }

  .site-main {
    padding: var(--space-3) var(--space-2) var(--space-4);
  }

  .main-top-rule {
    display: none;
  }

  .site-footer {
    padding: var(--space-2) var(--space-2) var(--space-3);
  }
}
